async (params, browser) => {
  // Open page
  await browser.open(`https://www.myfitnesspal.com/exercise/search?search=${params.exercise_name}`)

  // Wait for content
  await browser.waitForSelector('.exercise-item, [class*="Exercise"], li', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const results = Array.from(document.querySelectorAll('.exercise-item, [class*="Exercise"], li')).slice(0,10).map(el => { const name = el.querySelector('a, [class*="name"]')?.textContent?.trim()||el.textContent.trim(); const cal = el.querySelector('[class*="calories"], .calories-burned')?.textContent?.trim()||''; return { name: name.substring(0,100), calories_burned: cal }; }).filter(r=>r.name); return { search: '' + params.exercise_name + '', results }`)

  return page_data
}
